#!/usr/bin/env node
/**
 * SessionStart Hook — 前回セッションの要約を instructions ファイルに書き出す
 *
 * .github/sessions/ 内の最新セッションファイルと docs/sessions/ の共有文脈を読み、
 * .github/instructions/session-context.instructions.md に書き出す。
 * Copilot は .github/instructions/ を自動読込するため、
 * 前回の文脈と共有済みの文脈が自然にコンテキストに注入される。
 *
 * 公式入力: { timestamp, cwd, source, initialPrompt }
 *
 * 設計原則:
 * - 雛形のままのファイルは書き出さない
 * - セッションがない場合は instructions ファイルを削除（残存コンテキスト防止）
 * - エラー時は exit 0 で非ブロッキング
 */
'use strict';

const fs = require('fs');
const path = require('path');
const {
  SESSION_MAX_AGE_DAYS,
  readFileSafe,
  writeFileSafe,
  getProjectSessionsDir,
  getProjectSharedSessionsDir,
  ensureDir,
  findRecentSessions,
  findRecentSharedSessions,
  stripAnsi,
  log,
} = require('./lib/session-utils');

const INSTRUCTIONS_DIR = '.github/instructions';
const CONTEXT_FILENAME = 'session-context.instructions.md';

async function main() {
  const cwd = process.cwd();
  const sessionsDir = getProjectSessionsDir(cwd);
  const sharedSessionsDir = getProjectSharedSessionsDir(cwd);
  const instructionsDir = path.join(cwd, INSTRUCTIONS_DIR);
  const contextFile = path.join(instructionsDir, CONTEXT_FILENAME);

  if (!ensureDir(sessionsDir)) return;
  if (!ensureDir(sharedSessionsDir)) return;
  if (!ensureDir(instructionsDir)) return;

  const recentSessions = findRecentSessions(sessionsDir, SESSION_MAX_AGE_DAYS);
  const recentSharedSessions = findRecentSharedSessions(sharedSessionsDir, 3);

  if (recentSessions.length === 0 && recentSharedSessions.length === 0) {
    log('No recent sessions found');
    removeContextFile(contextFile);
    return;
  }

  if (recentSessions.length === 0 && recentSharedSessions.length > 0) {
    log(`No recent private sessions found, using shared archive: ${recentSharedSessions[0].basename}`);
  }

  let latest = null;
  let content = '';
  if (recentSessions.length > 0) {
    latest = recentSessions[0];
    log(`Found ${recentSessions.length} recent session(s), latest: ${latest.basename}`);
    content = stripAnsi(readFileSafe(latest.path) || '');

    if (!content || content.includes('[Session context goes here]') || isTemplateOnly(content)) {
      log('Session file is template-only, using shared archive if available');
      content = '';
      latest = null;
    }
  }

  if (!content.trim() && recentSharedSessions.length === 0) {
    removeContextFile(contextFile);
    return;
  }

  const instructionsContent = buildInstructionsContent(
    content,
    latest ? latest.basename : '',
    recentSessions,
    recentSharedSessions
  );
  writeFileSafe(contextFile, instructionsContent);
  log(`Wrote session context to: ${contextFile}`);
}

function buildInstructionsContent(sessionContent, sessionBasename, allSessions, sharedSessions) {
  const lines = [
    '---',
    'applyTo: "**"',
    '---',
    '',
    '# Previous Session Context',
    '',
  ];

  if (sessionContent && sessionContent.trim()) {
    lines.push(
      `> Auto-generated by sessionStart hook. Source: \`${sessionBasename}\``,
      '> This file is git-ignored and regenerated at each session start.',
      '',
      sessionContent
    );
  } else {
    lines.push('> No recent private session context was found.');
  }

  if (allSessions.length > 1) {
    lines.push('', '## Other Recent Sessions', '');
    allSessions.slice(1, 5).forEach((s) => {
      lines.push(`- \`${s.basename}\``);
    });
  }

  if (sharedSessions && sharedSessions.length > 0) {
    const latestShared = sharedSessions[0];
    lines.push('', '## Latest Shared Session Context', '');
    lines.push(`> Auto-generated by sessionStart hook. Source: \`${latestShared.basename}\``);
    lines.push('> This file is git-tracked and reflects the curated share archive.');
    lines.push('');
    lines.push(stripAnsi(readFileSafe(latestShared.path) || '').trim());

    if (sharedSessions.length > 1) {
      lines.push('', '## Other Recent Shared Sessions', '');
      sharedSessions.slice(1, 5).forEach((s) => {
        lines.push(`- \`${s.basename}\``);
      });
    }
  }

  return lines.join('\n') + '\n';
}

/**
 * YWT テンプレートのみ（Y/W/T が未記入）のセッションファイルを判定する。
 *
 * 判定方針:
 * - Y/W/T / Notes for Next Session / Context to Load を評価対象とする
 * - 空行・見出し・HTML コメント・Context の code fence 自体は評価対象外
 * - placeholder とみなす値は以下
 *   - `- [ ]`
 *   - `-` / `- `
 *   - `[relevant files]`
 * - それ以外のテキスト（自由記述、チェック済み checkbox、太字ヘッダ、実ファイルパス等）が
 *   1 行でもあれば false
 */
function isTemplateOnly(content) {
  if (!content) return false;

  const hasY = content.includes('### Y（やったこと）');
  const hasW = content.includes('### W（わかったこと）');
  const hasT =
    content.includes('### T（つぎにやること）') ||
    content.includes('### T（次にやること）');
  const hasNotes = content.includes('### Notes for Next Session');
  const hasContext = content.includes('### Context to Load');

  if (!hasY || !hasW || !hasT || !hasNotes || !hasContext) {
    return false;
  }

  const lines = content.split('\n');
  let currentSection = null;
  let inCodeFence = false;
  const contentLines = [];

  for (const line of lines) {
    const trimmed = line.trim();

    if (trimmed.startsWith('### ')) {
      currentSection = getTemplateSection(trimmed);
      continue;
    }

    if (!currentSection) continue;
    if (!trimmed) continue;
    if (trimmed.startsWith('<!--')) continue;

    if (trimmed.startsWith('```')) {
      if (currentSection !== 'context') {
        contentLines.push({ section: currentSection, line: trimmed });
      }
      inCodeFence = !inCodeFence;
      continue;
    }

    contentLines.push({ section: currentSection, line: trimmed });
  }

  if (contentLines.length === 0) return true;

  return contentLines.every(({ section, line }) => isPlaceholderLine(section, line));
}

function getTemplateSection(line) {
  if (line.includes('### Y（やったこと）')) return 'y';
  if (line.includes('### W（わかったこと）')) return 'w';
  if (line.includes('### T（つぎにやること）')) return 't';
  if (line.includes('### T（次にやること）')) return 't';
  if (line.includes('### Notes for Next Session')) return 'notes';
  if (line.includes('### Context to Load')) return 'context';
  return null;
}

function isPlaceholderLine(section, line) {
  if (section === 'context') {
    return line === '[relevant files]';
  }

  return /^-\s*(\[ \])?\s*$/.test(line);
}

function removeContextFile(filePath) {
  try {
    if (fs.existsSync(filePath)) {
      fs.unlinkSync(filePath);
      log(`Removed stale context file: ${filePath}`);
    }
  } catch (err) {
    log(`Failed to remove context file: ${err.message}`);
  }
}

if (require.main === module) {
  main().catch((err) => {
    log(`Error: ${err.message}`);
    process.exitCode = 0;
  });
}

module.exports = {
  isTemplateOnly,
  getTemplateSection,
  isPlaceholderLine,
  buildInstructionsContent,
};
